+
+        // ── Pre-validate all commits before encoding ──────────────────────
+        let mut prev_seq = self.last_commit_seq;
+        for commit in commits {
+            let seq = commit.commit_seq.0;
+            let txn = commit.txn_id.0;
+
+            if seq == u64::MAX || txn == u64::MAX {
